const timestamp = new Date().toLocaleString('es-MX', {
  timeZone: 'America/Mexico_City',
  year: 'numeric', month: '2-digit', day: '2-digit',
  hour: '2-digit', minute: '2-digit', second: '2-digit'
});

// Obtener texto de la respuesta de Gemini
// Ajusta según el nodo que uses. Opciones comunes:
let rawText = '';
try {
  // Si usas el nodo nativo Google Gemini Chat Model:
  rawText = $input.first().json.text || $input.first().json.output || '';

  // Si el texto viene vacío, intenta otras rutas comunes:
  if (!rawText) {
    const json = $input.first().json;
    rawText = json.response?.text || json.candidates?.[0]?.content?.parts?.[0]?.text || JSON.stringify(json);
  }
} catch (e) {
  rawText = JSON.stringify($input.first().json);
}

// Limpiar markdown si Gemini lo envolvió en backticks
rawText = rawText.replace(/```json\s*/gi, '').replace(/```\s*/gi, '').trim();

let insights = [];
try {
  const parsed = JSON.parse(rawText);
  insights = parsed.insights || [];
} catch (e) {
  // Si falla el parse, intentar extraer JSON del texto
  const match = rawText.match(/\{[\s\S]*"insights"[\s\S]*\}/);
  if (match) {
    try {
      insights = JSON.parse(match[0]).insights || [];
    } catch (e2) {
      // No se pudo parsear — retornar error como insight
      insights = [{
        tipo: 'negativo',
        titulo: 'Error al parsear respuesta de IA',
        diagnostico: 'La respuesta de Gemini no pudo ser parseada como JSON válido.',
        evidencia: rawText.substring(0, 200),
        recomendacion: 'Revisar el flujo de Insights IA en n8n.'
      }];
    }
  }
}

// Convertir a filas para Google Sheets
const rows = insights.map(insight => ({
  json: {
    timestamp,
    tipo: insight.tipo || 'negativo',
    titulo: insight.titulo || '',
    diagnostico: insight.diagnostico || '',
    evidencia: insight.evidencia || '',
    recomendacion: insight.recomendacion || '',
  }
}));

return rows;
